=<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
  <link href="https://fonts.googleapis.com/css2?family=Montserrat:wght@400;600;700&family=EB+Garamond:ital,wght@0,400;0,500;0,600;1,400&display=swap" rel="stylesheet">
  <style>
    * {
      margin: 0;
      padding: 0;
      box-sizing: border-box;
    }
    html, body {
      width: 1080px;
      height: 1350px;
      font-family: 'Poppins', sans-serif;
      overflow: hidden;
      position: relative;
      background-color: #000;
    }
    .image-container {
      position: relative;
      width: 100%;
      height: 100%;
      overflow: hidden;
    }
    .image-container::before {
      content: "";
      position: absolute;
      inset: 0;
      background-image: url("{{ $json.imagem1 }}");
      background-size: cover;
      background-position: center;
      filter: brightness(0.55);
      z-index: 1;
    }
    .overlay-dark {
      position: absolute;
      inset: 0;
      background: rgba(0, 0, 0, 0.0);
      z-index: 2;
    }
    .overlay-gradient {
      position: absolute;
      bottom: 0;
      left: 0;
      width: 100%;
      height: 20%;
      background: linear-gradient(to top, rgba(0,0,0,0.7), transparent);
      z-index: 3;
    }
    .mia-logo {
      position: absolute;
      top: 120px;
      right: 50px;
      text-align: right;
      z-index: 2;
    }
    .mia-logo img {
      width: 150px;
      height: auto;
      filter: drop-shadow(2px 2px 4px rgba(0,0,0,0.4));
    }
    .text-block {
      position: absolute;
      bottom: 100px;
      left: 80px;
      right: 80px;
      color: #fff;
      z-index: 5;
    }
    .text-block h2 {
      font-size: 64px;
      font-weight: 600;
      line-height: 1.0;
      text-shadow: 2px 2px 10px rgba(0,0,0,0.9);
      font-family: 'Montserrat', sans-serif;
    }
    .text-block h2 em {
      font-family: 'EB Garamond', serif;
      font-style: italic;
      font-weight: 500;
      font-size: 86px;
      color: #FFAE42;
      display: inline-block;
      letter-spacing: -2px;
    }
    .text-block h3 {
      font-size: 38px;
      font-weight: 400;
      line-height: 1.3;
      font-family: 'EB Garamond', serif;
      margin-top: 20px;
      color: #eaeaea;
      text-shadow: 1px 1px 6px rgba(0,0,0,0.8);
      letter-spacing: 1px;
    }
    .text-block h3 b {
      color: #ffffff;
      font-weight: 600;
      font-family: 'EB Garamond', serif;
    }
  </style>
</head>
<body>
  <div class="image-container">
    <div class="overlay-dark"></div>
    <div class="overlay-gradient"></div>
    <div class="mia-logo">
      <img src="{{ $('When Executed by Another Workflow').item.json.logo_empresa }}">
    </div>
    <div class="text-block">
      <h2>{{ $('Gera blocos de textos para os HTML\'s').item.json.html_imagem_1.parte_1 }}</h2>
      <h3>{{ $('Gera blocos de textos para os HTML\'s').item.json.html_imagem_1.parte_2 }}</h3>
    </div>
  </div>
</body>
</html>

=<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
  <link href="https://fonts.googleapis.com/css2?family=Montserrat:wght@400;600;700&family=EB+Garamond:ital,wght@0,400;0,500;0,600;1,400&display=swap" rel="stylesheet">
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    html, body {
      width: 1080px;
      height: 1350px;
      overflow: hidden;
      font-family: 'Montserrat', sans-serif;
      background-color: #1a1a1a;
      color: #ffffff;
      position: relative;
      display: flex;
      justify-content: center;
      align-items: center;
    }
    .image-top {
      position: absolute;
      top: 15px;
      left: 15px;
      right: 15px;
      bottom: 15px;
      background-image: url("{{ $json.imagem2 }}");
      background-size: cover;
      background-position: center;
      filter: brightness(0.85);
      z-index: 0;
      overflow: hidden;
    }
    .overlay {
      position: absolute;
      top: 15px;
      left: 15px;
      right: 15px;
      bottom: 15px;
      background: rgba(0, 0, 0, 0.75);
      border: 5px solid #FFAE42;
      z-index: 1;
      pointer-events: none;
    }
    .mia-logo {
      position: absolute;
      top: 100px;
      right: 80px;
      text-align: right;
      z-index: 3;
    }
    .mia-logo img {
      width: 150px;
      height: auto;
      filter: drop-shadow(2px 2px 4px rgba(0,0,0,0.4));
    }
    .text-section {
      position: absolute;
      bottom: 140px;
      left: 90px;
      right: 90px;
      z-index: 3;
      display: flex;
      flex-direction: column;
      gap: 25px;
      color: #ffffff;
      text-shadow: 0 2px 8px rgba(0,0,0,0.7);
      max-width: calc(1080px - 180px);
    }
    .text-bold {
      font-size: 42px;
      font-weight: 600;
      line-height: 1.3;
    }
    .text-bold b {
      color: #FFAE42;
    }
    .text-bold em {
      font-family: 'EB Garamond', serif;
      font-style: italic;
      font-weight: 500;
      color: #FFAE42;
      font-size: 54px;
      letter-spacing: -2px;
      display: inline-block;
    }
    .text-normal {
      font-size: 34px;
      line-height: 1.5;
      font-weight: 400;
    }
    .text-regular {
      font-size: 32px;
      line-height: 1.5;
      font-weight: 400;
      padding-left: 20px;
      border-left: 4px solid #FFAE42;
    }
  </style>
</head>
<body>
  <div class="image-top"></div>
  <div class="overlay"></div>
  <div class="mia-logo">
    <img src="{{ $('When Executed by Another Workflow').item.json.logo_empresa }}">
  </div>
  <div class="text-section">
    <div class="text-bold">{{ $('Gera blocos de textos para os HTML\'s').item.json.html_imagem_2.bloco_1 }}</div>
    <div class="text-normal">{{ $('Gera blocos de textos para os HTML\'s').item.json.html_imagem_2.bloco_2 }}</div>
    <div class="text-regular">{{ $('Gera blocos de textos para os HTML\'s').item.json.html_imagem_2.bloco_3 }}</div>
  </div>
</body>
</html>

=<!DOCTYPE html>
<html lang="pt-BR">
<head>
  <meta charset="UTF-8" />
  <link href="https://fonts.googleapis.com/css2?family=Montserrat:wght@400;600;700&family=EB+Garamond:ital,wght@0,400;1,400&display=swap" rel="stylesheet">
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    html, body {
      width: 1080px;
      height: 1350px;
      overflow: hidden;
      font-family: 'Montserrat', sans-serif;
      background: #000;
      color: white;
      display: flex;
      flex-direction: column;
      align-items: center;
      position: relative;
    }
    .image-container {
      position: relative;
      width: 95%;
      flex: 1 1 55%;
      margin-top: 30px;
      transition: all 0.3s ease;
    }
    .image-top {
      width: 100%;
      height: 100%;
      min-height: 550px;
      background: url("{{ $json.imagem3 }}") center/cover no-repeat;
      filter: brightness(0.8);
      transition: all 0.3s ease;
    }
    .mia-logo {
      position: absolute;
      bottom: 10px;
      right: 50px;
      text-align: right;
      z-index: 3;
    }
    .mia-logo img {
      width: 150px;
      height: auto;
      filter: drop-shadow(2px 2px 4px rgba(0,0,0,0.4));
    }
    .text-section {
      width: 90%;
      flex: 1 1 40%;
      display: flex;
      flex-direction: column;
      justify-content: flex-start;
      gap: 18px;
      margin-top: 30px;
    }
    .text-block {
      max-width: 90%;
      text-shadow: 1px 1px 5px rgba(0,0,0,0.4);
      line-height: 1.5;
    }
    /* bloco_1: apenas negrito, sem itálico, sem cor especial */
    .block-1 { font-size: 38px; font-weight: 700; }
    .block-1 em, .block-1 b { font-style: normal; color: inherit; font-family: inherit; font-size: inherit; letter-spacing: inherit; display: inline; }

    .block-2 { font-size: 28px; color: #e0e0e0; }
    .block-2 em, .block-2 b { font-style: normal; color: inherit; font-family: inherit; }

    .block-3 {
      font-size: 30px;
      text-decoration: underline;
      text-decoration-color: #FFAE42;
      text-underline-offset: 5px;
    }
  </style>
</head>
<body>
  <div class="image-container">
    <div class="image-top"></div>
    <div class="mia-logo">
      <img src="{{ $('When Executed by Another Workflow').item.json.logo_empresa }}">
    </div>
  </div>
  <div class="text-section">
    <div class="text-block block-1">{{ $('Gera blocos de textos para os HTML\'s').item.json.html_imagem_3.bloco_1 }}</div>
    <div class="text-block block-2">{{ $('Gera blocos de textos para os HTML\'s').item.json.html_imagem_3.bloco_2 }}</div>
    <div class="text-block block-3">{{ $('Gera blocos de textos para os HTML\'s').item.json.html_imagem_3.bloco_3 }}</div>
  </div>
</body>
</html>

