// --- Captura usa_blog do trigger ---
const usa_blog = $('When Executed by Another Workflow').first().json?.usa_blog ?? false;

// --- Captura o retorno da IA ---
const items = $input.all();
if (!items || items.length === 0) {
  throw new Error("⚠️ Nenhum retorno da IA encontrado.");
}
let resultado = null;
for (const item of items) {
  let output = item.output || item.json?.output || item.json?.text || '';
  if (!output) continue;

  // Remove possíveis blocos Markdown
  output = output.replace(/```json|```/g, '').trim();

  try {
    resultado = JSON.parse(output);
    break;
  } catch (err) {
    console.log('Erro ao parsear JSON:', err.message);
  }
}
if (!resultado) {
  throw new Error('❌ Não foi possível extrair JSON válido da resposta da IA');
}
// --- Valida estrutura ---
if (!resultado.textos || !resultado.imagens) {
  throw new Error('❌ JSON retornado está incompleto');
}
// --- Retorna estrutura simplificada ---
return [{
  json: {
    // Textos individuais
    texto_imagem_1: resultado.textos.imagem_1 || '',
    texto_imagem_2: resultado.textos.imagem_2 || '',
    texto_imagem_3: resultado.textos.imagem_3 || '',
    texto_imagem_4: resultado.textos.imagem_4 || '',
    texto_imagem_5: resultado.textos.imagem_5 || '',
    texto_imagem_6: resultado.textos.imagem_6 || '',

    // Imagens/queries individuais
    query_ou_imagem_1: resultado.imagens.imagem_1 || '',
    query_ou_imagem_2: resultado.imagens.imagem_2 || '',
    query_ou_imagem_3: resultado.imagens.imagem_3 || '',
    query_ou_imagem_4: resultado.imagens.imagem_4 || '',
    query_ou_imagem_5: resultado.imagens.imagem_5 || '',
    query_ou_imagem_6: resultado.imagens.imagem_6 || '',

    // Prompt para geração de imagem
    prompt_openai: resultado.prompt_openai || '',

    // Dado do trigger
    usa_blog: usa_blog
  }
}];

const items = $input.all();
const outputItems = [];

// Função para quebrar texto apenas em pontos finais REAIS
function quebrarFrases(texto) {
  if (!texto) return [];

  let textoProtegido = texto
    // Protege apenas decimais (número.número), NÃO números no fim de frase
    .replace(/(\d+)\.(\d+)/g, '$1___PONTO___$2')
    .replace(/\b(Dr|Sr|Sra|Prof|Art|Inc|Ltd|Ltda|S\.A|E\.U\.A|Jr)\./gi, '$1___PONTO___')
    .replace(/\b([A-Z]\.)+/g, (match) => match.replace(/\./g, '___PONTO___'));

  const frases = textoProtegido
    .split('.')
    .map(f => f.trim())
    .filter(f => f.length > 0)
    .map(f => f.replace(/___PONTO___/g, '.'));

  return frases;
}

for (const item of items) {
  const data = item.json;

  // =======================
  // IMAGEM 1 (CAPA)
  // parte_1 = SEMPRE apenas a 1ª frase
  // parte_2 = o restante das frases
  // =======================
  const texto1 = data.texto_imagem_1 || '';
  const frases1 = quebrarFrases(texto1);

  let parte1 = '';
  let parte2 = '';

  if (frases1.length >= 2) {
    parte1 = frases1[0] + '.';
    parte2 = frases1.slice(1).join('. ') + '.';
  } else {
    // fallback: split simples por ". "
    const splitSimples = texto1.split('. ');
    if (splitSimples.length >= 2) {
      parte1 = splitSimples[0] + '.';
      parte2 = splitSimples.slice(1).join('. ');
    } else {
      parte1 = texto1;
      parte2 = '';
    }
  }

  // IMAGEM 1: injeta <em> na palavra longa (CSS do HTML1 já estiliza com cor e tamanho)
  let textoComItalico1 = parte1;
  let textoComItalico2 = parte2;

  const palavrasGrandes1 = parte1.match(/\b\p{L}{8,}\b/gu);
  if (palavrasGrandes1?.length) {
    const palavra = palavrasGrandes1[0];
    textoComItalico1 = parte1.replace(
      new RegExp(`\\b${palavra}\\b`, 'iu'),
      '<em>$&</em>'
    );
  } else {
    const palavrasGrandes2 = parte2.match(/\b\p{L}{8,}\b/gu);
    if (palavrasGrandes2?.length) {
      const palavra = palavrasGrandes2[0];
      textoComItalico2 = parte2.replace(
        new RegExp(`\\b${palavra}\\b`, 'iu'),
        '<em>$&</em>'
      );
    }
  }

  const htmlImagem1 = {
    parte_1: textoComItalico1,
    parte_2: textoComItalico2
  };

  // =======================
  // FUNÇÕES AUXILIARES
  // =======================
  function aplicarEnfases(bloco1, bloco2, bloco3) {

    // BLOCO 1 — apenas <em> na primeira palavra longa técnica
    if (bloco1) {
      const palavrasTecnicas = bloco1.match(/\b\p{L}{8,}\b/gu);
      if (palavrasTecnicas?.length) {
        const palavra = palavrasTecnicas[0];
        bloco1 = bloco1.replace(
          new RegExp(`\\b${palavra}\\b`, 'iu'),
          '<em>$&</em>'
        );
      }
    }

    // BLOCO 2 — <b> em números + <em> em palavra técnica
    if (bloco2) {
      bloco2 = bloco2.replace(/\b(\d+[%]?)\b/g, '<b>$1</b>');
      bloco2 = bloco2.replace(
        /\b(\d+\s+(?:horas?|dias?|meses|anos?|minutos?|vezes|pontos?|reais|porcentos?))\b/gi,
        '<b>$1</b>'
      );

      const palavrasTecnicas = bloco2.replace(/<[^>]+>/g, '').match(/\b\p{L}{8,}\b/gu);
      if (palavrasTecnicas?.length) {
        const palavra = palavrasTecnicas[0];
        bloco2 = bloco2.replace(
          new RegExp(`(?<!<[^>]*)\\b${palavra}\\b`, 'iu'),
          '<em>$&</em>'
        );
      }
    }

    // BLOCO 3 — apenas <b> em números
    if (bloco3) {
      bloco3 = bloco3.replace(/\b(\d+[%]?)\b/g, '<b>$1</b>');
      bloco3 = bloco3.replace(
        /\b(\d+\s+(?:horas?|dias?|meses|anos?|minutos?|vezes|pontos?|reais|porcentos?))\b/gi,
        '<b>$1</b>'
      );
    }

    return {
      bloco_1: bloco1.trim(),
      bloco_2: bloco2.trim(),
      bloco_3: bloco3.trim()
    };
  }

  function processarTextoDesenvolvimento(texto) {
    if (!texto) return { bloco_1: '', bloco_2: '', bloco_3: '' };

    const frases = quebrarFrases(texto);

    let b1 = '', b2 = '', b3 = '';

    if (frases.length === 3) {
      [b1, b2, b3] = frases.map(f => f + '.');
    } else if (frases.length === 2) {
      b1 = frases[0] + '.';
      const palavras = frases[1].split(' ');
      const metade = Math.ceil(palavras.length / 2);
      b2 = palavras.slice(0, metade).join(' ') + '.';
      b3 = palavras.slice(metade).join(' ') + '.';
    } else if (frases.length === 1) {
      const palavras = texto.split(' ');
      const t = Math.floor(palavras.length / 3);
      b1 = palavras.slice(0, t).join(' ');
      b2 = palavras.slice(t, t * 2).join(' ');
      b3 = palavras.slice(t * 2).join(' ');
    } else {
      const porBloco = Math.ceil(frases.length / 3);
      b1 = frases.slice(0, porBloco).join('. ') + '.';
      b2 = frases.slice(porBloco, porBloco * 2).join('. ') + '.';
      b3 = frases.slice(porBloco * 2).join('. ') + '.';
    }

    return aplicarEnfases(b1, b2, b3);
  }

  // =======================
  // IMAGENS 2–5
  // =======================
  const htmlImagem2 = processarTextoDesenvolvimento(data.texto_imagem_2);
  const htmlImagem3 = processarTextoDesenvolvimento(data.texto_imagem_3);
  const htmlImagem4 = processarTextoDesenvolvimento(data.texto_imagem_4);
  const htmlImagem5 = processarTextoDesenvolvimento(data.texto_imagem_5);

  // =======================
  // IMAGEM 6 (FECHAMENTO)
  // 3 partes: 1ª colorida, 2ª e 3ª normais
  // =======================
  let texto6 = data.texto_imagem_6 || '';
  const frasesTexto6 = quebrarFrases(texto6);

  let htmlTexto6 = '';
  if (frasesTexto6.length >= 3) {
    const f1 = frasesTexto6[0] + '.';
    const f2 = frasesTexto6[1] + '.';
    const f3 = frasesTexto6.slice(2).join('. ') + '.';
    htmlTexto6 = `<span style="color:#FFAE42;font-weight:bold;">${f1}</span> ${f2} ${f3}`;
  } else if (frasesTexto6.length === 2) {
    const f1 = frasesTexto6[0] + '.';
    const f2 = frasesTexto6[1] + '.';
    htmlTexto6 = `<span style="color:#FFAE42;font-weight:bold;">${f1}</span> ${f2}`;
  } else if (frasesTexto6.length === 1) {
    htmlTexto6 = `<span style="color:#FFAE42;font-weight:bold;">${frasesTexto6[0]}.</span>`;
  }

  const htmlImagem6 = { texto_completo: htmlTexto6 };

  // =======================
  // OUTPUT FINAL
  // =======================
  outputItems.push({
    json: {
      html_imagem_1: htmlImagem1,
      html_imagem_2: htmlImagem2,
      html_imagem_3: htmlImagem3,
      html_imagem_4: htmlImagem4,
      html_imagem_5: htmlImagem5,
      html_imagem_6: htmlImagem6,

      query_ou_imagem_1: data.query_ou_imagem_1,
      query_ou_imagem_2: data.query_ou_imagem_2,
      query_ou_imagem_3: data.query_ou_imagem_3,
      query_ou_imagem_4: data.query_ou_imagem_4,
      query_ou_imagem_5: data.query_ou_imagem_5,
      query_ou_imagem_6: data.query_ou_imagem_6
    }
  });
}

return outputItems;

// --- Captura a resposta do Unsplash e a query original ---
const results = $json.results || [];
const queryKey = Object.keys($json).find(k => k.startsWith('query_slide_'));
const originalQuery = queryKey ? $json[queryKey] : ($json.query || '');

// --- Seleciona uma imagem aleatória ou o único resultado ---
const randomIndex = results.length > 0 ? Math.floor(Math.random() * results.length) : 0;
const selectedImage = results[randomIndex] || $json;

// --- Extrai a melhor URL disponível ---
const imageUrl = selectedImage.urls?.regular ||
                 selectedImage.urls?.small ||
