const items = $input.all();
const outputItems = [];

// Função robusta para quebrar frases apenas em pontos finais REAIS
function quebrarFrases(texto) {
  if (!texto) return [];

  let textoProtegido = texto
    .replace(/(\d+)\./g, '$1___PONTO___')
    .replace(/\b(Dr|Sr|Sra|Prof|Art|Inc|Ltd|Ltda|S\.A|E\.U\.A|Jr)\./gi, '$1___PONTO___')
    .replace(/\b([A-Z]\.)+/g, (match) => match.replace(/\./g, '___PONTO___'));

  const frases = textoProtegido
    .split('.')
    .map(f => f.trim())
    .filter(f => f.length > 0)
    .map(f => f.replace(/___PONTO___/g, '.'));

  return frases;
}

for (const item of items) {
  const data = item.json;

  // =======================
  // IMAGEM 1 (CAPA)
  // Apenas 1ª frase, em maiúsculo, com highlight na 1ª palavra longa
  // =======================
  const frases1 = quebrarFrases(data.texto_imagem_1 || '');
  let textoPrincipal1 = ((frases1[0] || data.texto_imagem_1 || '') + '.').toUpperCase();

  const palavraDestaque = textoPrincipal1.match(/\b\p{L}{5,}\b/gu);
  if (palavraDestaque?.length) {
    const palavra = palavraDestaque[0];
    const escapada = palavra.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    textoPrincipal1 = textoPrincipal1.replace(
      new RegExp(`\\b${escapada}\\b`, 'gu'),
      `<span class="highlight">${palavra}</span>`
    );
  }

  const htmlImagem1 = {
    texto_principal: `<b>${textoPrincipal1}</b>`,
    texto_secundario: '',
    texto_apoio: ''
  };

  // =======================
  // FUNÇÕES AUXILIARES
  // =======================
  function aplicarEnfases(b1, b2, b3) {

    // BLOCO 1 — apenas 1 <em> na primeira palavra técnica longa
    // CSS de cada HTML cuida da cor e tamanho
    if (b1) {
      const palavra = b1.match(/\b\p{L}{8,}\b/gu)?.[0];
      if (palavra) {
        const esc = palavra.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
        b1 = b1.replace(new RegExp(`\\b${esc}\\b`, 'iu'), '<em>$&</em>');
      }
    }

    // BLOCO 2 — apenas <b> em números se existirem
    // Sem sublinhado, sem itálico colorido
    if (b2) {
      b2 = b2.replace(/\b(\d+%?)\b/g, '<b>$1</b>');
    }

    // BLOCO 3 — sem nenhuma ênfase extra
    // O HTML já diferencia este bloco visualmente por tamanho/cor de container

    return {
      texto_principal: b1.trim(),
      texto_secundario: b2.trim(),
      texto_apoio: b3.trim()
    };
  }

  function processarTexto(texto) {
    if (!texto) return { texto_principal: '', texto_secundario: '', texto_apoio: '' };

    const frases = quebrarFrases(texto);
    let b1 = '', b2 = '', b3 = '';

    if (frases.length === 3) {
      b1 = frases[0] + '.';
      b2 = frases[1] + '.';
      b3 = frases[2] + '.';
    } else if (frases.length === 2) {
      b1 = frases[0] + '.';
      const palavras = frases[1].split(' ');
      const metade = Math.ceil(palavras.length / 2);
      b2 = palavras.slice(0, metade).join(' ') + '.';
      b3 = palavras.slice(metade).join(' ') + '.';
    } else if (frases.length === 1) {
      const palavras = texto.split(' ');
      const t = Math.floor(palavras.length / 3);
      b1 = palavras.slice(0, t).join(' ');
      b2 = palavras.slice(t, t * 2).join(' ');
      b3 = palavras.slice(t * 2).join(' ');
    } else {
      const por = Math.ceil(frases.length / 3);
      b1 = frases.slice(0, por).join('. ') + '.';
      b2 = frases.slice(por, por * 2).join('. ') + '.';
      b3 = frases.slice(por * 2).join('. ') + '.';
    }

    return aplicarEnfases(b1, b2, b3);
  }

  const htmlImagem2 = processarTexto(data.texto_imagem_2);
  const htmlImagem3 = processarTexto(data.texto_imagem_3);
  const htmlImagem4 = processarTexto(data.texto_imagem_4);
  const htmlImagem5 = processarTexto(data.texto_imagem_5);

  // =======================
  // IMAGEM 6 (FECHAMENTO)
  // Texto completo em maiúsculo, 1ª palavra longa em destaque
  // =======================
  let texto6 = (data.texto_imagem_6 || '').toUpperCase();

  const palavraDestaque6 = texto6.match(/\b\p{L}{8,}\b/gu)?.[0];
  if (palavraDestaque6) {
    const esc = palavraDestaque6.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
    texto6 = texto6.replace(
      new RegExp(`\\b${esc}\\b`, 'gu'),
      `<em>${palavraDestaque6}</em>`
    );
  }

  const htmlImagem6 = { texto_principal: texto6 };

  outputItems.push({
    json: {
      html_imagem_1: htmlImagem1,
      html_imagem_2: htmlImagem2,
      html_imagem_3: htmlImagem3,
      html_imagem_4: htmlImagem4,
      html_imagem_5: htmlImagem5,
      html_imagem_6: htmlImagem6,

      query_ou_imagem_1: data.query_ou_imagem_1,
      query_ou_imagem_2: data.query_ou_imagem_2,
      query_ou_imagem_3: data.query_ou_imagem_3,
      query_ou_imagem_4: data.query_ou_imagem_4,
      query_ou_imagem_5: data.query_ou_imagem_5,
      query_ou_imagem_6: data.query_ou_imagem_6
    }
  });
}

return outputItems;

