const items = $input.all();
const outputItems = [];

function limparTexto(txt = '') {
  return txt.replace(/\s+/g, ' ').trim();
}

for (const item of items) {
  const d = item.json;

  // ======================
  // IMAGEM 1 - Primeira parte em negrito, resto normal
  // Exemplo: "A bebida do Toguro virou case de hype: o "sabor energético sem energético" que fez a internet querer provar só pra ter opinião"
  // Fica: <b>A bebida do Toguro virou case de hype:</b> o "sabor energético sem energético" que fez a internet querer provar só pra ter opinião
  // ======================
  let t1 = limparTexto(d.texto_imagem_1 || '');
  const partes1 = t1.split(':');

  let textoFormatado1 = '';
  if (partes1.length >= 2) {
    // Primeira parte até os dois pontos fica em negrito
    textoFormatado1 = `<b>${partes1[0]}:</b>${partes1.slice(1).join(':')}`;
  } else {
    // Se não tiver ":", pega a primeira frase
    const frases1 = t1.split(/[.!?]/).filter(f => f.trim());
    if (frases1.length >= 2) {
      textoFormatado1 = `<b>${frases1[0].trim()}.</b> ${frases1.slice(1).join('. ').trim()}`;
    } else {
      textoFormatado1 = `<b>${t1}</b>`;
    }
  }

  const htmlImagem1 = {
    texto_completo: textoFormatado1
  };

  // ======================
  // IMAGEM 2 - Texto normal + Texto em negrito
  // ======================
  let t2 = limparTexto(d.texto_imagem_2 || '');
  const frases2 = t2.split('.').map(f => f.trim()).filter(Boolean);

  let bloco1_img2 = '';
  let bloco2_img2 = '';

  if (frases2.length >= 2) {
    bloco1_img2 = frases2[0] + '.';
    bloco2_img2 = `<b>${frases2.slice(1).join('. ').trim()}.</b>`;
  } else if (frases2.length === 1) {
    const palavras = frases2[0].split(' ');
    const metade = Math.ceil(palavras.length / 2);
    bloco1_img2 = palavras.slice(0, metade).join(' ') + '.';
    bloco2_img2 = `<b>${palavras.slice(metade).join(' ')}.</b>`;
  }

  const htmlImagem2 = {
    bloco_1: bloco1_img2,
    bloco_2: bloco2_img2
  };

  // ======================
  // IMAGEM 3 - Texto amarelo + Texto branco sublinhado
  // ======================
  let t3 = limparTexto(d.texto_imagem_3 || '');
  const frases3 = t3.split('.').map(f => f.trim()).filter(Boolean);

  let bloco1_img3 = '';
  let bloco2_img3 = '';

  if (frases3.length >= 2) {
    bloco1_img3 = frases3[0] + '.';
    bloco2_img3 = frases3.slice(1).join('. ') + '.';
  } else if (frases3.length === 1) {
    const palavras = frases3[0].split(' ');
    const metade = Math.ceil(palavras.length / 2);
    bloco1_img3 = palavras.slice(0, metade).join(' ') + '.';
    bloco2_img3 = palavras.slice(metade).join(' ') + '.';
  }

  const htmlImagem3 = {
    bloco_1: bloco1_img3,
    bloco_2: bloco2_img3
  };

  // ======================
  // IMAGEM 4 - Dois textos brancos sublinhados
  // ======================
  let t4 = limparTexto(d.texto_imagem_4 || '');
  const frases4 = t4.split('.').map(f => f.trim()).filter(Boolean);

  let bloco1_img4 = '';
  let bloco2_img4 = '';

  if (frases4.length >= 2) {
    bloco1_img4 = frases4[0] + '.';
    bloco2_img4 = frases4.slice(1).join('. ') + '.';
  } else if (frases4.length === 1) {
    const palavras = frases4[0].split(' ');
    const metade = Math.ceil(palavras.length / 2);
    bloco1_img4 = palavras.slice(0, metade).join(' ') + '.';
    bloco2_img4 = palavras.slice(metade).join(' ') + '.';
  }

  const htmlImagem4 = {
    bloco_1: bloco1_img4,
    bloco_2: bloco2_img4
  };

  // ======================
  // IMAGEM 5 - Mantém estrutura
  // ======================
  let t5 = limparTexto(d.texto_imagem_5 || '');
  const frases5 = t5.split('.').map(f => f.trim()).filter(Boolean);

  let bloco1_img5 = '';
  let bloco2_img5 = '';

  if (frases5.length >= 2) {
    bloco1_img5 = frases5[0] + '.';
    bloco2_img5 = frases5.slice(1).join('. ') + '.';
  } else if (frases5.length === 1) {
    const palavras = frases5[0].split(' ');
    const metade = Math.ceil(palavras.length / 2);
    bloco1_img5 = palavras.slice(0, metade).join(' ') + '.';
    bloco2_img5 = palavras.slice(metade).join(' ') + '.';
  }

  const htmlImagem5 = {
    bloco_1: bloco1_img5,
    bloco_2: bloco2_img5
  };

  // ======================
  // IMAGEM 6 - Mantém estrutura
  // ======================
  let t6 = limparTexto(d.texto_imagem_6 || '');
  const frases6 = t6.split('.').map(f => f.trim()).filter(Boolean);

  let bloco1_img6 = '';
  let bloco2_img6 = '';

  if (frases6.length >= 2) {
    bloco1_img6 = frases6[0] + '.';
    bloco2_img6 = frases6.slice(1).join('. ') + '.';
  } else if (frases6.length === 1) {
    bloco1_img6 = frases6[0] + '.';
    bloco2_img6 = '';
  }

  const htmlImagem6 = {
    bloco_1: bloco1_img6,
    bloco_2: bloco2_img6
  };

  // ======================
  // RETORNO FINAL
  // ======================
  outputItems.push({
    json: {
      html_imagem_1: htmlImagem1,
      html_imagem_2: htmlImagem2,
      html_imagem_3: htmlImagem3,
      html_imagem_4: htmlImagem4,
      html_imagem_5: htmlImagem5,
      html_imagem_6: htmlImagem6,

      query_ou_imagem_1: d.query_ou_imagem_1,
      query_ou_imagem_2: d.query_ou_imagem_2,
      query_ou_imagem_3: d.query_ou_imagem_3,
      query_ou_imagem_4: d.query_ou_imagem_4,
      query_ou_imagem_5: d.query_ou_imagem_5,
      query_ou_imagem_6: d.query_ou_imagem_6
    }
  });
}

return outputItems;

