const items = $input.all();
const outputItems = [];

function limparTexto(txt = '') {
  return txt.replace(/\s+/g, ' ').trim();
}

function destacarPrimeiraRelevante(texto) {
  const palavrasIgnoradas = [
    'O', 'A', 'OS', 'AS', 'UM', 'UMA', 'DE', 'DA', 'DO', 'DOS', 'DAS',
    'EM', 'NO', 'NA', 'NOS', 'NAS', 'POR', 'PARA', 'COM', 'SEM',
    'E', 'OU', 'MAS', 'QUE', 'SE', 'COMO', 'MAIS', 'MENOS',
    'ESTA', 'ESTE', 'ESSA', 'ESSE', 'ISSO', 'AQUELA', 'AQUELE',
    'AO', 'AOS', 'À', 'ÀS', 'PELO', 'PELA', 'PELOS', 'PELAS',
    'FOI', 'SÃO', 'TEM', 'VAI', 'JÁ', 'ATÉ', 'SUA', 'SEU', 'SEUS', 'SUAS'
  ];

  let textoUpper = texto.toUpperCase();
  const palavras = textoUpper.split(' ').filter(p => p.length > 0);

  for (let palavra of palavras) {
    const palavraLimpa = palavra.replace(/[.,;:!?]/g, '');
    if (palavraLimpa.length > 3 && !palavrasIgnoradas.includes(palavraLimpa)) {
      return textoUpper.replace(
        palavra,
        `<span class="destaque">${palavra}</span>`
      );
    }
  }

  for (let palavra of palavras) {
    const palavraLimpa = palavra.replace(/[.,;:!?]/g, '');
    if (palavraLimpa.length > 2) {
      return textoUpper.replace(
        palavra,
        `<span class="destaque">${palavra}</span>`
      );
    }
  }

  return textoUpper;
}

// ================================
// MAPEAMENTO DE RAMO → TEXTO CAPA
// ================================
function gerarTextoCapa(ramo) {
  const r = (ramo || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

  if (r.includes('imobili')) {
    return 'O que movimentou o mercado Imobiliário esta semana';
  }
  if (r.includes('tributar') || r.includes('tribut')) {
    return 'O que movimentou o mercado Tributário esta semana';
  }
  if (r.includes('inteligencia artificial') || r.includes('automac')) {
    return 'O que movimentou o mercado de Inteligência Artificial esta semana';
  }

  // Fallback genérico para ramos não mapeados
  return `O que movimentou o mercado de ${ramo} esta semana`;
}

const ramo = $('When Executed by Another Workflow').first().json?.dados_empresa
