    bloco_1: destacarPrimeiraRelevante(frases5[0] ? frases5[0] + '.' : t5),
    bloco_2: frases5.length >= 2 ? frases5.slice(1).join('. ').trim() + '.' : ''
  };

  // ================================
  // IMAGEM 6 — Fundo branco
  // ================================
  let t6 = limparTexto(d.texto_imagem_6 || '');
  const frases6 = t6.split('.').map(f => f.trim()).filter(Boolean);
  const htmlImagem6 = {
    bloco_1: destacarPrimeiraRelevante(frases6[0] ? frases6[0] + '.' : t6),
    bloco_2: frases6.length >= 2 ? frases6.slice(1).join('. ').trim() + '.' : ''
  };

  // ================================
  // RETORNO FINAL
  // ================================
  outputItems.push({
    json: {
      html_imagem_1: htmlImagem1,
      html_imagem_2: htmlImagem2,
      html_imagem_3: htmlImagem3,
      html_imagem_4: htmlImagem4,
      html_imagem_5: htmlImagem5,
      html_imagem_6: htmlImagem6,

      query_ou_imagem_1: d.query_ou_imagem_1,
      query_ou_imagem_2: d.query_ou_imagem_2,
      query_ou_imagem_3: d.query_ou_imagem_3,
      query_ou_imagem_4: d.query_ou_imagem_4,
      query_ou_imagem_5: d.query_ou_imagem_5,
      query_ou_imagem_6: d.query_ou_imagem_6
    }
  });
}

return outputItems;
